mapper.select:
SELECT
    (SELECT COUNT(*) FROM warehouses WHERE is_active = true
        AND id = #{warehouseId}
    ) as "activeWarehouses",
    (SELECT COUNT(*) FROM inventory_item
        WHERE state_id NOT IN ('DISCARDED', 'DAMAGED_SEVERE')
        AND primary_fc = #{warehouseId}
    ) as "totalSkus",
    (SELECT COUNT(*) FROM inventory_item
        WHERE available_quantity <= low_stock_threshold
        AND state_id NOT IN ('DISCARDED', 'DAMAGED_SEVERE')
        AND primary_fc = #{warehouseId}
    ) as "lowStockItems",
    (SELECT COUNT(*) FROM inventory_item
        WHERE available_quantity = 0
        AND state_id NOT IN ('DISCARDED', 'DAMAGED_SEVERE')
        AND primary_fc = #{warehouseId}
    ) as "outOfStockItems",
    (SELECT COUNT(*) FROM fulfillment_orders
        WHERE state_id IN ('INITIATED', 'PICKING', 'PACKING')
        AND warehouse_id = #{warehouseId}
    ) as "pendingFulfillments",
    (SELECT COUNT(*) FROM fulfillment_orders
        WHERE state_id = 'SHIPPED'
        AND DATE(shipped_at) = CURRENT_DATE
        AND warehouse_id = #{warehouseId}
    ) as "shippedToday",
    (SELECT COUNT(*) FROM pick_lists
        WHERE status = 'PENDING'
        AND warehouse_id = #{warehouseId}
    ) as "pendingPickLists"

SELECT count(*)
FROM inventory_item inv
LEFT JOIN products p ON inv.product_id = p.id

    inv.state_id NOT IN ('DISCARDED', 'DAMAGED_SEVERE')
    AND inv.primary_fc = #{warehouseId}
    AND inv.product_id = #{productId}
    AND inv.sku = #{sku}
    AND inv.state_id = #{stateId}
    AND inv.available_quantity <= inv.low_stock_threshold

SELECT inv.id as "inventoryId", inv.sku as "sku", inv.product_id as "productId", inv.variant_id as "variantId", inv.quantity as "totalQuantity", inv.available_quantity as "availableQuantity", inv.reserved_quantity as "reservedQuantity", inv.damaged_quantity as "damagedQuantity", inv.inbound_quantity as "inboundQuantity", inv.low_stock_threshold as "lowStockThreshold", inv.status as "inventoryStatus", inv.state_id as "stateId", inv.primary_fc as "warehouseId", p.name as "productName", p.brand as "brand", p.state_id as "productState", c.name as "categoryName", w.warehouse_name as "warehouseName", w.warehouse_code as "warehouseCode", w.city as "warehouseCity", CASE WHEN inv.available_quantity <= inv.low_stock_threshold THEN true ELSE false END as "isLowStock", CASE WHEN inv.available_quantity = 0 THEN true ELSE false END as "isOutOfStock" FROM inventory_item inv LEFT JOIN products p ON inv.product_id = p.id LEFT JOIN categories c ON p.category_id = c.id LEFT JOIN warehouses w ON inv.primary_fc = w.id
inv.state_id NOT IN ('DISCARDED', 'DAMAGED_SEVERE') AND inv.primary_fc = #{warehouseId} AND inv.product_id = #{productId} AND inv.sku = #{sku} AND inv.state_id = #{stateId} AND inv.available_quantity <= inv.low_stock_threshold
${orderby} ${pagination}

SELECT count(*)
FROM fulfillment_orders fo

    AND fo.warehouse_id = #{warehouseId}
    AND fo.state_id = #{stateId}
    AND fo.priority = #{priority}
    AND fo.assigned_picker_id = #{assignedPickerId}
    AND fo.carrier = #{carrier}

SELECT fo.id as "fulfillmentId", fo.order_id as "orderId", fo.state_id as "fulfillmentState", fo.priority as "priority", fo.fulfillment_type as "fulfillmentType", fo.total_items as "totalItems", fo.total_weight_grams as "totalWeightGrams", fo.assigned_picker_id as "assignedPicker", fo.assigned_packer_id as "assignedPacker", fo.pick_started_at as "pickStartedAt", fo.pick_completed_at as "pickCompletedAt", fo.pack_started_at as "packStartedAt", fo.pack_completed_at as "packCompletedAt", fo.shipped_at as "shippedAt", fo.carrier as "carrier", fo.tracking_number as "trackingNumber", fo.shipping_method as "shippingMethod", fo.estimated_ship_date as "estimatedShipDate", fo.estimated_delivery_date as "estimatedDeliveryDate", fo.notes as "notes", fo.created_time as "createdTime", fo.warehouse_id as "warehouseId", w.warehouse_name as "warehouseName", w.warehouse_code as "warehouseCode", o.order_number as "orderNumber", o.state_id as "orderState", o.total_amount as "orderAmount", o.currency as "orderCurrency", o.customer_id as "customerId", u.first_name as "customerFirstName", u.last_name as "customerLastName", sh.state_id as "shippingStatus", sh.current_location as "currentLocation" FROM fulfillment_orders fo LEFT JOIN warehouses w ON fo.warehouse_id = w.id LEFT JOIN orders o ON fo.order_id = o.id LEFT JOIN user_profiles u ON o.customer_id = u.id LEFT JOIN shipments sh ON sh.order_id = o.id
AND fo.warehouse_id = #{warehouseId} AND fo.state_id = #{stateId} AND fo.priority = #{priority} AND fo.assigned_picker_id = #{assignedPickerId} AND fo.carrier = #{carrier}
${orderby} ${pagination}

SELECT count(*)
FROM pick_lists pl

    AND pl.fulfillment_order_id = #{fulfillmentOrderId}
    AND pl.warehouse_id = #{warehouseId}
    AND pl.status = #{status}
    AND pl.assigned_to = #{assignedTo}

SELECT pl.id as "pickListId", pl.fulfillment_order_id as "fulfillmentOrderId", pl.warehouse_id as "warehouseId", pl.assigned_to as "assignedTo", pl.status as "pickStatus", pl.item_count as "itemCount", pl.picked_count as "pickedCount", pl.started_at as "startedAt", pl.completed_at as "completedAt", pl.notes as "notes", pl.created_time as "createdTime", w.warehouse_name as "warehouseName", w.warehouse_code as "warehouseCode", fo.order_id as "orderId", fo.state_id as "fulfillmentState", fo.priority as "fulfillmentPriority", fo.total_items as "fulfillmentTotalItems", o.order_number as "orderNumber", o.customer_id as "customerId" FROM pick_lists pl LEFT JOIN warehouses w ON pl.warehouse_id = w.id LEFT JOIN fulfillment_orders fo ON pl.fulfillment_order_id = fo.id LEFT JOIN orders o ON fo.order_id = o.id
AND pl.fulfillment_order_id = #{fulfillmentOrderId} AND pl.warehouse_id = #{warehouseId} AND pl.status = #{status} AND pl.assigned_to = #{assignedTo}
${orderby} ${pagination}

SELECT count(*) FROM warehouses

    AND id = #{warehouseId}
    AND warehouse_type = #{warehouseType}
    AND is_active = CAST(#{isActive} AS boolean)

SELECT w.id as "warehouseId", w.warehouse_code as "warehouseCode", w.warehouse_name as "warehouseName", w.warehouse_type as "warehouseType", w.city as "city", w.state as "state", w.max_capacity_units as "maxCapacityUnits", w.current_utilization_pct as "currentUtilizationPct", w.is_active as "isActive", COALESCE(loc_stats.total_locations, 0) as "totalLocations", COALESCE(loc_stats.active_locations, 0) as "activeLocations", COALESCE(loc_stats.total_capacity, 0) as "totalLocationCapacity", COALESCE(loc_stats.used_capacity, 0) as "usedLocationCapacity", COALESCE(inv_stats.total_skus, 0) as "totalSkus", COALESCE(inv_stats.total_units, 0) as "totalUnits", COALESCE(inv_stats.low_stock_count, 0) as "lowStockCount", COALESCE(ful_stats.pending_fulfillments, 0) as "pendingFulfillments" FROM warehouses w LEFT JOIN ( SELECT warehouse_id, COUNT(*) as total_locations, COUNT(*) FILTER (WHERE is_active = true) as active_locations, SUM(capacity_units) as total_capacity, SUM(current_units) as used_capacity FROM warehouse_locations GROUP BY warehouse_id ) loc_stats ON loc_stats.warehouse_id = w.id LEFT JOIN ( SELECT primary_fc, COUNT(*) as total_skus, SUM(available_quantity) as total_units, COUNT(*) FILTER (WHERE available_quantity <= low_stock_threshold) as low_stock_count FROM inventory_item WHERE state_id NOT IN ('DISCARDED', 'DAMAGED_SEVERE') GROUP BY primary_fc ) inv_stats ON inv_stats.primary_fc = w.id LEFT JOIN ( SELECT warehouse_id, COUNT(*) as pending_fulfillments FROM fulfillment_orders WHERE state_id IN ('INITIATED', 'PICKING', 'PACKING') GROUP BY warehouse_id ) ful_stats ON ful_stats.warehouse_id = w.id
AND w.id = #{warehouseId} AND w.warehouse_type = #{warehouseType} AND w.is_active = CAST(#{isActive} AS boolean)
${orderby} ${pagination}

SELECT count(*)
FROM warehouse_inventory wi
JOIN warehouse_locations wl ON wi.location_id = wl.id

    AND wl.warehouse_id = #{warehouseId}
    AND wl.zone = #{zone}
    AND wl.location_type = #{locationType}

SELECT wi.id as "warehouseInventoryId", wi.location_id as "locationId", wi.product_id as "productId", wi.variant_id as "variantId", wi.sku as "sku", wi.quantity_on_hand as "quantityOnHand", wi.quantity_reserved as "quantityReserved", wi.quantity_available as "quantityAvailable", wi.quantity_damaged as "quantityDamaged", wi.quantity_in_transit as "quantityInTransit", wi.last_counted_at as "lastCountedAt", wl.location_code as "locationCode", wl.zone as "zone", wl.aisle as "aisle", wl.shelf as "shelf", wl.bin as "bin", wl.location_type as "locationType", wl.capacity_units as "locationCapacity", wl.current_units as "locationCurrentUnits", p.name as "productName", p.brand as "brand", w.warehouse_name as "warehouseName", w.warehouse_code as "warehouseCode" FROM warehouse_inventory wi JOIN warehouse_locations wl ON wi.location_id = wl.id JOIN warehouses w ON wl.warehouse_id = w.id LEFT JOIN products p ON wi.product_id = p.id
AND wl.warehouse_id = #{warehouseId} AND wl.zone = #{zone} AND wl.location_type = #{locationType}
${orderby} ${pagination}

SELECT count(*)
FROM inventory_movements im
LEFT JOIN inventory_item ii ON im.inventory_item_id = ii.id
WHERE im.type = 'INBOUND'
AND im.fulfillment_center_id = #{warehouseId}
AND ii.supplier_id = #{supplierId}
